import { cx } from 'emotion';
import React, { forwardRef } from 'react';
import {
  Box,
  type CommonProps,
  type PropsWithHTMLElement,
  type ExpandProps,
} from '@contentful/f36-core';
import type * as CSS from 'csstype';

import { getTableStyles } from './Table.styles';
import { TableContextProvider } from './tableContext';

export type TableInternalProps = CommonProps & {
  /**
   * @default 'inline'
   */
  layout?: 'inline' | 'embedded';
  /**
   * @default 'top'
   */
  verticalAlign?: Extract<
    CSS.Property.VerticalAlign,
    'baseline' | 'bottom' | 'middle' | 'top'
  >;
};

export type TableProps = PropsWithHTMLElement<TableInternalProps, 'table'>;

export const Table = forwardRef<HTMLTableElement, ExpandProps<TableProps>>(
  (
    {
      children,
      className,
      layout = 'inline',
      testId = 'cf-ui-table',
      verticalAlign = 'top',
      ...otherProps
    },
    forwardedRef,
  ) => {
    const styles = getTableStyles();

    return (
      <Box
        cellPadding="0"
        cellSpacing="0"
        {...otherProps}
        as="table"
        display="table"
        ref={forwardedRef}
        className={cx(styles.root, styles[layout], className)}
        testId={testId}
      >
        <TableContextProvider value={{ verticalAlign }}>
          {children}
        </TableContextProvider>
      </Box>
    );
  },
);

Table.displayName = 'Table';
import { css } from 'emotion';
import tokens from '@contentful/f36-tokens';

export const getTableStyles = () => ({
  inline: css({
    borderRadius: tokens.borderRadiusMedium,
    boxShadow: `0 0 0 1px ${tokens.gray200}`,
    'th:first-child': {
      borderTopLeftRadius: tokens.borderRadiusMedium,
    },
    'th:last-child': {
      borderTopRightRadius: tokens.borderRadiusMedium,
    },
    'tr:last-child td:first-child': {
      borderBottomLeftRadius: tokens.borderRadiusMedium,
    },
    'tr:last-child td:last-child': {
      borderBottomRightRadius: tokens.borderRadiusMedium,
    },
  }),
  embedded: css({
    borderBottom: `1px solid ${tokens.gray200}`,
  }),
  root: css({
    width: '100%',
  }),
});
import { createContext, useContext } from 'react';
import { TableProps } from './Table';

export type TableContext = {
  verticalAlign?: TableProps['verticalAlign'];
};

export const TableContext = createContext<TableContext>({});

export const useTableContext = () => {
  const context = useContext(TableContext);

  return context;
};

export const TableContextProvider = TableContext.Provider;
import React, { forwardRef, type ReactNode } from 'react';
import {
  Box,
  type CommonProps,
  type PropsWithHTMLElement,
  type ExpandProps,
} from '@contentful/f36-core';

export type TableBodyInternalProps = CommonProps & {
  children: ReactNode;
};

export type TableBodyProps = PropsWithHTMLElement<
  TableBodyInternalProps,
  'tbody'
>;

function _TableBody(
  { className, children, testId = 'cf-ui-table-body', ...otherProps },
  forwardedRef,
) {
  return (
    <Box
      {...otherProps}
      as="tbody"
      className={className}
      ref={forwardedRef}
      testId={testId}
    >
      {children}
    </Box>
  );
}

_TableBody.displayName = 'TableBody';

export const TableBody = forwardRef<
  HTMLTableSectionElement,
  ExpandProps<TableBodyProps>
>(_TableBody);
import { cx } from 'emotion';
import React, { forwardRef, useMemo, useState } from 'react';
import {
  type CommonProps,
  type PropsWithHTMLElement,
  type ExpandProps,
  type PolymorphicComponent,
} from '@contentful/f36-core';
import { Text, Caption, type TextProps } from '@contentful/f36-typography';
import {
  SortAscendingIcon,
  SortDescendingIcon,
  SortIcon,
} from '@contentful/f36-icons';
import { getTextFromChildren } from '@contentful/f36-utils';

import { useTableCellContext } from './TableCellContext';
import { getTableCellStyles } from './TableCell.styles';
import { useTableContext } from '../tableContext';

export enum TableCellSorting {
  Ascending = 'ascending',
  Descending = 'descending',
}

const SortingIconMap = {
  [TableCellSorting.Ascending]: SortAscendingIcon,
  [TableCellSorting.Descending]: SortDescendingIcon,
};

export type TableCellInternalProps = CommonProps & {
  align?: 'center' | 'left' | 'right';
  children?: React.ReactNode;
  isSortable?: boolean;
  sortDirection?: TableCellSorting;
  width?: string | number;
  /**
   * Aria label for the sort button when isSortable is set
   */
  sortButtonAriaLabel?: string;
} & Pick<TextProps, 'isTruncated' | 'isWordBreak'>;

export type TableCellProps = PropsWithHTMLElement<
  TableCellInternalProps,
  'th' | 'td'
>;

function _TableCell(
  {
    align = 'left',
    children,
    className,
    isSortable,
    sortDirection,
    testId = 'cf-ui-table-cell',
    sortButtonAriaLabel,
    ...otherProps
  }: TableCellProps,
  forwardedRef: React.Ref<any>,
) {
  const [showSorting, setShowSorting] = useState(false);
  const { as, name: context, offsetTop } = useTableCellContext();
  const { verticalAlign } = useTableContext();
  const SortingIcon = SortingIconMap[sortDirection];
  const isTableHead = context === 'head';
  const styles = getTableCellStyles({
    isSortable: isTableHead ? isSortable : undefined,
    isTableHead,
    align,
    verticalAlign,
  });
  const BaseComponent = isTableHead ? Caption : Text;
  const sortableProps = isSortable
    ? {
        'aria-sort': (sortDirection ?? 'none') as
          | 'none'
          | 'ascending'
          | 'descending'
          | 'other',
        onBlur: () => setShowSorting(false),
        onFocus: () => setShowSorting(true),
        onMouseEnter: () => setShowSorting(true),
        onMouseLeave: () => setShowSorting(false),
      }
    : {};
  const columnName = useMemo(() => getTextFromChildren(children), [children]);
  let tableCellContent = children;

  if (isSortable) {
    tableCellContent = (
      <button
        aria-label={
          sortButtonAriaLabel ??
          `Sort ${
            sortDirection === TableCellSorting.Ascending
              ? TableCellSorting.Descending
              : TableCellSorting.Ascending
          } by ${columnName}`
        }
        className={styles.button}
        type="button"
      >
        {children}
        {sortDirection ? (
          <SortingIcon size="tiny" variant="secondary" />
        ) : (
          <SortIcon
            aria-hidden={!showSorting}
            className={styles.sortIcon(showSorting)}
            size="tiny"
            variant="secondary"
          />
        )}
      </button>
    );
  }

  return (
    <BaseComponent
      {...otherProps}
      {...sortableProps}
      as={as}
      className={cx(styles.container, className)}
      ref={forwardedRef}
      style={{
        ...otherProps.style,
        top: offsetTop || undefined,
      }}
      testId={testId}
    >
      {tableCellContent}
    </BaseComponent>
  );
}

_TableCell.displayName = 'TableCell';

export const TableCell: PolymorphicComponent<
  ExpandProps<TableCellInternalProps>,
  'th' | 'td'
> = forwardRef(_TableCell);
import { createContext, useContext } from 'react';

export type TableCellContextOption = {
  name: 'body' | 'head';
  as: 'td' | 'th';
  offsetTop: number | string;
};

export const contextOptions: {
  body: TableCellContextOption;
  head: TableCellContextOption;
} = {
  body: { name: 'body', as: 'td', offsetTop: 0 },
  head: { name: 'head', as: 'th', offsetTop: 0 },
};

export const TableCellContext = createContext(contextOptions.body);

export const useTableCellContext = () => {
  const context = useContext(TableCellContext);

  return context;
};

export const TableCellContextProvider = TableCellContext.Provider;
