  }),
  sortIcon: (showSorting: boolean) =>
    css({
      fill: tokens.gray400,
      opacity: showSorting ? 1 : 0,
      transition: `opacity ${tokens.transitionEasingCubicBezier} ${tokens.transitionDurationDefault}`,
    }),
});
import { cx } from 'emotion';
import React, { forwardRef } from 'react';
import {
  Box,
  type CommonProps,
